const user = { name: 'Alice', age: 30, role: 'admin' };

// Without destructuring
const name = user.name;
const age  = user.age;

// With destructuring — one statement
const { name, age } = user;

console.log(name); // 'Alice'
console.log(age);  // 30

// Regular destructure in body
function greet(user) {
  const { name, role } = user;
  return `Hello ${name} (${role})`;
}

// Equivalent: destructure in the parameter
function greet({ name, role }) {
  return `Hello ${name} (${role})`;
}

// Without destructuring
function UserCard(props) {
  return (
    <div>
      <img src={props.avatarUrl} alt={props.name} />
      <h2>{props.name}</h2>
      <p>{props.bio}</p>
    </div>
  );
}

// With destructuring in the signature
function UserCard({ avatarUrl, name, bio }) {
  return (
    <div>
      <img src={avatarUrl} alt={name} />
      <h2>{name}</h2>
      <p>{bio}</p>
    </div>
  );
}

function InputWrapper(props) {
  const { label, id, ...inputProps } = props;  // keep inputProps for spreading
  return (
    <div className="field">
      <label htmlFor={id}>{label}</label>
      <input id={id} {...inputProps} />
    </div>
  );
}

function Button({ label, variant = 'primary', size = 'md', disabled = false }) {
  return (
    <button
      className={`btn btn-${variant} btn-${size}`}
      disabled={disabled}
    >
      {label}
    </button>
  );
}

// variant, size, disabled use defaults:
<Button label="Save" />

// Override any subset:
<Button label="Delete" variant="danger" size="sm" />

// Rename 'size' to 'iconSize' to avoid shadowing a local variable
function Icon({ name, size: iconSize = 24 }) {
  return <svg width={iconSize} height={iconSize}><use href={`#icon-${name}`} /></svg>;
}

// Rename a prop with a reserved JS keyword (e.g. a data-API field named 'class')
function Tag({ label, class: cssClass }) {
  return <span className={cssClass}>{label}</span>;
}

// One level deep — acceptable
function ProfileCard({ user: { name, email, avatarUrl } }) {
  return (
    <div>
      <img src={avatarUrl} alt={name} />
      <p>{name} — {email}</p>
    </div>
  );
}

// Two levels deep — hard to read, especially with defaults
function ProfileCard({ user: { name, address: { city, country = 'US' } } }) {
  // ...
}

// Prefer flat over deep:
function ProfileCard({ name, email, avatarUrl, city, country = 'US' }) {
  // ...
}

function CoordinateLabel({ point }) {
  const [x, y, z = 0] = point;   // array destructure in the body
  return <span>({x}, {y}, {z})</span>;
}

<CoordinateLabel point={[10, 20]} />
// renders: (10, 20, 0)

// Intercept 'className'; forward everything else to <button>
function PrimaryButton({ className = '', children, ...rest }) {
  return (
    <button className={`btn-primary ${className}`} {...rest}>
      {children}
    </button>
  );
}

// All three attrs are forwarded via rest:
<PrimaryButton type="submit" disabled={saving} onClick={handleSave}>
  Save changes
</PrimaryButton>

// Hard to read — all on one line
function ProductCard({ name, price, imageUrl, category, inStock = true, onAddToCart, onWishlist }) {
  // ...
}

// Readable — one prop per line
function ProductCard({
  name,
  price,
  imageUrl,
  category,
  inStock = true,
  onAddToCart,
  onWishlist,
}) {
  // ...
}

// Inline type annotation
function UserCard({ name, age, isAdmin = false }: {
  name: string;
  age: number;
  isAdmin?: boolean;
}) {
  return <p>{name} {isAdmin ? '(admin)' : ''}</p>;
}

// Separate interface — preferred for reuse and readability
interface UserCardProps {
  name: string;
  age: number;
  isAdmin?: boolean;
}

function UserCard({ name, age, isAdmin = false }: UserCardProps) {
  return <p>{name} {isAdmin ? '(admin)' : ''}</p>;
}

function PriceDisplay({ price, currency = 'USD', discountPercent = 0 }) {
  const discounted = price * (1 - discountPercent / 100);
  const formatted  = new Intl.NumberFormat('en-US', {
    style: 'currency',
    currency,
  }).format(discounted);

  const hasDiscount = discountPercent > 0;

  return (
    <div>
      {hasDiscount && (
        <del>{new Intl.NumberFormat('en-US', { style: 'currency', currency }).format(price)}</del>
      )}
      <strong>{formatted}</strong>
      {hasDiscount && <span className="badge">-{discountPercent}%</span>}
    </div>
  );
}

// Public API uses generic 'value'; internally use 'selectedDate'
function DatePicker({ value: selectedDate, onChange: onDateChange, min: minDate, max: maxDate }) {
  return (
    <input
      type="date"
      value={selectedDate}
      onChange={e => onDateChange(e.target.value)}
      min={minDate}
      max={maxDate}
    />
  );
}

// Usage — generic names outside
<DatePicker
  value={startDate}
  onChange={setStartDate}
  min="2024-01-01"
  max="2024-12-31"
/>

function Notification({
  title,
  message,
  type = 'info',
  icon = null,
  onDismiss = null,
}) {
  const colourMap = { info: 'blue', success: 'green', warning: 'amber', error: 'red' };
  const colour = colourMap[type] ?? 'blue';

  return (
    <div className={`notification notification-${colour}`} role="alert">
      {icon && <span className="icon">{icon}</span>}
      <div>
        <strong>{title}</strong>
        <p>{message}</p>
      </div>
      {onDismiss && (
        <button onClick={onDismiss} aria-label="Dismiss">×</button>
      )}
    </div>
  );
}

import { forwardRef } from 'react';

const FancyInput = forwardRef(function FancyInput(
  { label, className = '', ...inputProps },  // ← destructure props normally
  ref                                         // ← ref is the second argument
) {
  return (
    <div className="field">
      <label>{label}</label>
      <input
        ref={ref}
        className={`fancy-input ${className}`}
        {...inputProps}
      />
    </div>
  );
});

class UserCard extends React.Component {
  render() {
    const { name, role, avatarUrl } = this.props;  // destructure in render body
    return (
      <div>
        <img src={avatarUrl} alt={name} />
        <p>{name} — {role}</p>
      </div>
    );
  }
}

function SearchInput({ onSearch }) {
  function handleChange({ target: { value } }) {  // destructure event.target.value
    onSearch(value);
  }

  return <input type="search" onChange={handleChange} />;
}

function TagSelector({ tags, onTagToggle }) {
  return (
    <ul>
      {tags.map(({ id, label, isSelected }) => (   // destructure each tag object
        <li key={id}>
          <button
            className={isSelected ? 'active' : ''}
            onClick={() => onTagToggle(id)}
          >
            {label}
          </button>
        </li>
      ))}
    </ul>
  );
}

function ArticleCard({
  // Required props
  title,
  author,
  publishedAt,

  // Optional with defaults
  excerpt = '',
  coverUrl = null,
  tags = [],
  readTimeMinutes = null,

  // Rename: public 'href' becomes internal 'articleUrl'
  href: articleUrl,

  // Callbacks default to null (render conditionally)
  onBookmark = null,
  onShare = null,

  // Rest forwarded to the outer <article> element
  ...articleProps
}) {
  // Derived value
  const readTime = readTimeMinutes != null
    ? `${readTimeMinutes} min read`
    : null;

  return (
    <article {...articleProps}>
      {coverUrl && <img src={coverUrl} alt={title} />}
      <h2><a href={articleUrl}>{title}</a></h2>
      <p>By {author} · {publishedAt}{readTime && ` · ${readTime}`}</p>
      {excerpt && <p>{excerpt}</p>}
      {tags.length > 0 && (
        <ul>{tags.map(t => <li key={t}>{t}</li>)}</ul>
      )}
      <div>
        {onBookmark && <button onClick={onBookmark}>Bookmark</button>}
        {onShare    && <button onClick={onShare}>Share</button>}
      </div>
    </article>
  );
}
